+            fnx_available: false,
+            is_wasm: true,
+            strict_fallback: true,
+            ..Default::default()
+        };
+        let result = lint_fnx_config(&input);
+        // Off mode should not trigger any warnings even with bad combinations
+        assert!(!result.has_errors());
+        assert!(!result.has_warnings());
+    }
